module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);
    reg [7:0] dividend_abs;
    reg [7:0] divisor_abs;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [7:0] NEG_DIVISOR;
    reg start_cnt;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dividend_abs <= 0;
            divisor_abs <= 0;
            SR <= 0;
            cnt <= 0;
            NEG_DIVISOR <= 0;
            start_cnt <= 0;
            res_valid <= 0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_abs <= dividend;
            divisor_abs <= divisor;
            SR <= {dividend_abs, 1'b0};
            cnt <= 4'b0001;
            NEG_DIVISOR <= -divisor_abs;
            start_cnt <= 1;
            res_valid <= 1;
        end
        else if (start_cnt) begin
            if (cnt[3]) begin
                cnt <= 0;
                start_cnt <= 0;
                SR <= {SR[14:0], 1'b0};
            end
            else begin
                cnt <= cnt + 1;
                start_cnt <= 1;
                {SR, NEG_DIVISOR} <= {SR[14:0], NEG_DIVISOR[6:0], 1'b0};
            end
        end
        else begin
            res_valid <= 0;
        end
    end
    assign result = {SR[15:8], SR[7:0]};
endmodule
